export const commissionFactoryAdvertiserAdapter = new CommissionFactoryAdvertiserAdapter();
registerAdapter(commissionFactoryAdvertiserAdapter);

// ---------------------------------------------------------------------------
// Local helpers
// ---------------------------------------------------------------------------

function defaultFrom(now: Date): string {
  return new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000).toISOString();
}

function toStatusList(
  v?: TransactionStatus | TransactionStatus[],
): TransactionStatus[] | undefined {
  if (v === undefined) return undefined;
  return Array.isArray(v) ? v : [v];
}

export const _internals = {
  toTransaction,
  toProgramme,
  toDiscoveredBrand,
  rollupByAffiliate,
  mapTransactionStatus,
  mapPerfStatus,
  mapPromotionStatus,
  computeAgeDays,
  nullableIso,
  toAmount,
  extractTransactions,
  extractPromotions,
  defaultFrom,
};
